import test from 'node:test';
import assert from 'node:assert/strict';

import { JobStore } from '../src/job-store.mjs';
import { JobRunner } from '../src/job-runner.mjs';

test('the store rejects completion from an attempt the watchdog replaced', () => {
  const store = new JobStore();
  store.enqueue('export-10', { format: 'csv' });

  const original = store.claim();
  assert.equal(store.requeueRunning('export-10', 'worker heartbeat lost'), true);
  const replacement = store.claim();

  assert.equal(store.complete('export-10', original.attempt, 'old-result'), false);
  assert.deepEqual(store.get('export-10'), {
    id: 'export-10',
    payload: { format: 'csv' },
    status: 'running',
    attempt: replacement.attempt,
    result: null,
    lastError: null
  });
  assert.equal(store.complete('export-10', replacement.attempt, 'new-result'), true);
  assert.equal(store.get('export-10').result, 'new-result');
});

test('the runner identifies the claim when reporting successful work', async () => {
  const calls = [];
  const store = {
    claim() {
      return { id: 'export-11', payload: { format: 'pdf' }, attempt: 7 };
    },
    complete(...args) {
      calls.push(args);
      return true;
    },
    fail() {
      throw new Error('unexpected failure');
    }
  };

  const runner = new JobRunner(store, async () => 'rendered');
  assert.equal((await runner.runNext()).status, 'succeeded');
  assert.deepEqual(calls, [['export-11', 7, 'rendered']]);
});
